import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { TextField, Button, Typography, Box } from "@mui/material";
import axios from "axios";

const EditDrug = () => {
    const { id } = useParams(); // Lấy ID thuốc từ URL
    const [drug, setDrug] = useState({
        code: "",
        name: "",
        typeId: "",
        price: "",
        unit: "",
        description: "",
    });

    // Gọi API lấy dữ liệu cũ khi mở trang
    useEffect(() => {
        axios
            .get(`http://localhost:5000/api/drugs/${id}`)
            .then((res) => setDrug(res.data))
            .catch((err) => console.error("Lỗi tải dữ liệu thuốc:", err));
    }, [id]);

    // Cập nhật giá trị khi nhập
    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    // Gửi dữ liệu đã chỉnh sửa lên server
    const handleSubmit = (e) => {
        e.preventDefault();
        axios
            .put(`http://localhost:5000/api/drugs/${id}`, drug)
            .then(() => alert("Cập nhật thành công"))
            .catch((err) => console.error("Lỗi cập nhật thuốc:", err));
    };

    return (
        <Box sx={{ p: 3 }}>
            <Typography variant="h4" gutterBottom>
                Chỉnh sửa thuốc
            </Typography>
            <form onSubmit={handleSubmit}>
                <TextField
                    fullWidth
                    label="Mã thuốc"
                    name="code"
                    value={drug.code}
                    onChange={handleChange}
                    required
                    sx={{ mb: 2 }}
                />
                <TextField
                    fullWidth
                    label="Tên thuốc"
                    name="name"
                    value={drug.name}
                    onChange={handleChange}
                    required
                    sx={{ mb: 2 }}
                />
                <TextField
                    fullWidth
                    label="ID loại thuốc"
                    name="typeId"
                    value={drug.typeId}
                    onChange={handleChange}
                    required
                    sx={{ mb: 2 }}
                />
                <TextField
                    fullWidth
                    label="Giá"
                    name="price"
                    value={drug.price}
                    onChange={handleChange}
                    required
                    sx={{ mb: 2 }}
                />
                <TextField
                    fullWidth
                    label="Đơn vị"
                    name="unit"
                    value={drug.unit}
                    onChange={handleChange}
                    required
                    sx={{ mb: 2 }}
                />
                <TextField
                    fullWidth
                    label="Mô tả"
                    name="description"
                    value={drug.description}
                    onChange={handleChange}
                    multiline
                    rows={4}
                    required
                    sx={{ mb: 2 }}
                />
                <Button variant="contained" color="primary" type="submit">
                    Lưu lại
                </Button>
            </form>
        </Box>
    );
};

export default EditDrug;
